if( page.variables.isAdmin || page.variables.isTestEnvironment || page.variables.hideNewFeatures || page.variables.isNonTech) {
  //disableFileOperations.setValue(false);
  await actions.setPageVariable("disableFileOperations", false)
} 
else {
  const tempExceptionList = page.variables.bulkUploadExceptionList;
  for(let i = 0; i < tempExceptionList.length; i++) {
    if(tempExceptionList[i].email === globals.currentUser.email) {
      const dateString = tempExceptionList[i].startTime;
      const expirationTime = tempExceptionList[i].expirationInMinutes;
      const givenDate = new Date(dateString);
      const currentDate = new Date();
      // Allow Bulk Operation for negative expirationTime
      if(expirationTime < 0) {
        //disableFileOperations.setValue(false);
        await actions.setPageVariable("disableFileOperations", false)
        return;
      }
      // Calculate the difference in milliseconds
      const differenceInMilliseconds = currentDate - givenDate;
      // Convert expiration minutes to milliseconds
      const timeInMilliseconds = expirationTime * 60 * 1000;
      // Check if the difference is within expiration time
      const isWithinExpirationTime = (differenceInMilliseconds > 0 && differenceInMilliseconds <= timeInMilliseconds);
      if(isWithinExpirationTime) {
       // disableFileOperations.setValue(false);
         await actions.setPageVariable("disableFileOperations", false)

        return;
      }
    }
  }
 // disableFileOperations.setValue(true);
  await actions.setPageVariable("disableFileOperations", true)
}
